import{_ as a,c as n,a as i,o as e}from"./app-CEcM0piI.js";const l={};function d(p,s){return e(),n("div",null,s[0]||(s[0]=[i(`<ul><li>javabean类：用于描述一类事物的类</li><li>测试类：用来检查其他类是否书写正确，带有main方法的类，是程序的主入口</li><li>工具类：不是用来描述一类事物，而是帮我们做一些事情的类<br> 工具类通常需要私有化构造方法，因为创建它的对象没有意义<br> 工具类通常使用static修饰方法<br> 静态方法只能访问静态变量和静态方法<br> 静态方法中没有this关键字</li></ul><p>用来描述一类事物的类，专业叫做：Javabean类。 在Javabean类中，是不写main方法的。 在以前，编写main方法的类，叫做测试类 我们可以在测试类中创建javabean类的对象并进行赋值调用。</p><p>一个java文件中可以定义多个class类，且只能有一个类是public修饰，而且public修饰的类的类名必须是文件名</p><h1 id="继承" tabindex="-1"><a class="header-anchor" href="#继承"><span>继承</span></a></h1><p>java不允许多继承,但允许多层继承 Java中提供一个关键字extends，用这个关键字，我们可以让一个类和另一个类建立起继承关系。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Student extends Person {}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Student称为子类（派生类），Person称为父类(基类或超类)。</p><h3 id="子类能够继承父类的内容" tabindex="-1"><a class="header-anchor" href="#子类能够继承父类的内容"><span>子类能够继承父类的内容</span></a></h3><ul><li>构造方法: 不管是不是private修饰符修饰的都不能继承</li><li>成员变量: 不管是不是私有都可以被继承,但私有的无法访问</li><li>成员方法: 非私有的能继承,私有的不能继承 ![[Clip_2024-07-05_10-31-04.png]]</li></ul><p>父类的构造方法不会被子类继承<br> 子类中所有构造方法默认先访问父类的无参构造再执行自己<br> 这是防止子类初始化是可能会用到从父类那里继承来的数据<br> 需要在子类的构造方法中第一行显式写出super（）<br> 不写也是存在的，显式写出来必须在第一行<br> 如果想要调用父类的有参构造必须手动写super调用</p><h3 id="super指针" tabindex="-1"><a class="header-anchor" href="#super指针"><span>super指针</span></a></h3><p>和this指针类似,super指针代表的是父类 但子类中只能调用一次super,在子类中只能调用一个父类,所以无法使用super调用到父类的父类</p><h3 id="重写" tabindex="-1"><a class="header-anchor" href="#重写"><span>重写</span></a></h3><p>只有添加到虚方法表中的方法才可重写 在继承体系中，子类出现了和父类中一模一样的方法声明，我们就称子类这个方法是重写的方法。 方法名和形参列表必须一致 但返回值类型可以不一致,但返回值类型子类必须小于等于父类 ( 即如果返回值是继承的父子类,父类函数的返回值是另一个继承关系子类时,子类重写的返回值不能是那一个继承关系的父类)</p><p><strong>错误:</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Animal{}</span></span>
<span class="line"><span>class Dog extends Animal{}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class A{</span></span>
<span class="line"><span>	public Dog func(){}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class B extends A{</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public Animal func(){}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>子类重写父类的方法时,访问权限子类必须大于等于父类(public&gt;protected&gt;无) 私有方法不能被重写 子类不能重写父类的静态方法，如果重写会报错的。</p><h4 id="override重写注解" tabindex="-1"><a class="header-anchor" href="#override重写注解"><span>@Override重写注解</span></a></h4><p>@Override是放在重写后的方法上，校验子类重写时语法是否正确。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class A{</span></span>
<span class="line"><span>	public void func(){}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>class B extends A{</span></span>
<span class="line"><span>	@Override</span></span>
<span class="line"><span>	public void func(){}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在一个类的构造函数中可以调用它的其他的构造函数,但这样只能写在第一行,否则会报错 放在第一行后如果有父类的话编译器会进行优化即在此构造中不调用super()无参构造,而在子类调用的构造方法里调用super()</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Student{</span></span>
<span class="line"><span>	String name;</span></span>
<span class="line"><span>	int age;</span></span>
<span class="line"><span>	String school;</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	public Student(){</span></span>
<span class="line"><span>		this(name,null,&quot;hello&quot;);    //调用其他的构造函数,必须放在第一行</span></span>
<span class="line"><span>		System.out.println(&quot;1234&quot;);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	public Student(String name,int age,String school{</span></span>
<span class="line"><span>		this.name=name;</span></span>
<span class="line"><span>		this.age=age;</span></span>
<span class="line"><span>		this.school = school;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>判断类型: <code>x instanceof T</code>判断x是不是T类型,返回布尔值 java14新特性 <code>x instanceof T y</code>如果x是T类型则将其转换为T类型后保存为y变量,如果不是T类型就返回false</p><h2 id="包" tabindex="-1"><a class="header-anchor" href="#包"><span>包</span></a></h2><p>公司域名反写+包的作用，需要全部英文小写，见名知意。如: com.itheima.domain</p><p>管理类的文件夹用来管理各种不同功能的Java类，方便后期代码维护.相当于命名空间</p><p>使用其中的Student类</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>con.itheima.domain.Student s=new com.itheima.domain.Student();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>import con.itheima.domain.Student;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="final" tabindex="-1"><a class="header-anchor" href="#final"><span>final</span></a></h2><p>修饰方法表明该方法时最终方法不能被重写</p><p>修饰类表明该类时最终类,不能被继承</p><p>修饰变量表明这个变量代表常量,只能被赋值一次,以后都不可被修改 基本数据类型：变量的值不能修改 引用数据类型：地址值不能修改，内部的属性值可以修改</p><h2 id="权限修饰符" tabindex="-1"><a class="header-anchor" href="#权限修饰符"><span>权限修饰符</span></a></h2><p>四种权限作用范围由小到大 private&lt;默认 ( 缺省 ) &lt;protectedd&lt; public 默认也就是不写明权限修饰符</p><p>权限可用的范围</p><table><thead><tr><th>修饰符</th><th>同一个类中</th><th>同一个包中其他类</th><th>不同包下的子类</th><th>不同包下的无关类</th></tr></thead><tbody><tr><td>private</td><td>Y</td><td></td><td></td><td></td></tr><tr><td>default</td><td>Y</td><td>Y</td><td></td><td></td></tr><tr><td>protected</td><td>Y</td><td>Y</td><td>Y</td><td></td></tr><tr><td>public</td><td>Y</td><td>Y</td><td>Y</td><td>Y</td></tr></tbody></table><h3 id="构造代码块" tabindex="-1"><a class="header-anchor" href="#构造代码块"><span>构造代码块</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Student {</span></span>
<span class="line"><span>	private String name;</span></span>
<span class="line"><span>	private int age;</span></span>
<span class="line"><span>	{</span></span>
<span class="line"><span>		System.out.println(&quot;开始创建对象了&quot;);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	public Student(){}</span></span>
<span class="line"><span>	public Student (String name,int age){</span></span>
<span class="line"><span>		this.name=name;</span></span>
<span class="line"><span>		this.age=age;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>把构造函数都会用到的代码以代码块的方式写到成员变量区里面,这样就不用写重复的代码了,相当于委托构造函数</p><h4 id="静态代码块" tabindex="-1"><a class="header-anchor" href="#静态代码块"><span>静态代码块</span></a></h4><p>需要通过static关键字修饰，随着类的加载而加载，并且自动触发、只执行一次</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>static{</span></span>
<span class="line"><span>	/*code*/</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="抽象类" tabindex="-1"><a class="header-anchor" href="#抽象类"><span>抽象类</span></a></h3><p><code>abstract</code>关键字 被<code>abstract</code>修饰的成员函数可以不给出实现只给出声明,其子类继承后必须重写此函数否则会报错</p><p>被<code>abstract</code>修饰的类就是抽象类</p><ul><li>抽象类不能实例化</li><li>抽象类中不一定有抽象方法，有抽象方法的类一定是抽象类</li><li>可以有构造方法</li><li>抽象类的子类 要么重写抽象类中的<strong>所有</strong>抽象方法 要么是抽象类</li></ul><h3 id="接口" tabindex="-1"><a class="header-anchor" href="#接口"><span>接口</span></a></h3><p>接口是对行为的抽象 <code>public interface 接口名{}</code> 接口不能实例化 接口和类之间是实现关系，通过implements关键字表示 <code>public class 类名 implements 接口名{}</code>表明该类对此接口进行实现 接口的子类也被称为实现类: 要么重写接口中的所有抽象方法 要么是抽象类</p><p>接口和类的实现关系，可以单实现，也可以多实现。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class 类名 implements 接口名1,接口名2{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>实现类还可以在继承一个类的同时实现多个接口。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class 类名 extends 父类 implements 接口名1,接口名2{}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>接口中的成员变量只能是常量,没有构造方法,成员方法只能是抽象方法</p><p>接口和接口之间的关系可以是单继承也可以是多继承,如果类实现的是最下面的子接口时就需要实现它上面的所有抽象方法</p><p>因为接口重写时需要实现其中的所有抽象方法,若要对接口进行更改那么继承这个接口的所有类也要更改</p><h4 id="默认方法" tabindex="-1"><a class="header-anchor" href="#默认方法"><span>默认方法</span></a></h4><p>再jdk8之后就允许接口中定义默认方法,需要使用到<code>default</code>关键字修饰用来解决接口升级的问题 默认方法不是抽象方法，所以不强制被重写。但是如果被重写，重写的时候去掉default关键字 如果实现了多个接口，多个接口中存在相同名字的默认方法，子类就必须对该方法进行重写</p><h4 id="静态方法" tabindex="-1"><a class="header-anchor" href="#静态方法"><span>静态方法</span></a></h4><p>接口中使用<code>static</code>修饰的成员方法</p><p>静态方法只能通过接口名调用，不能通过实现类名或者对象名调用 ( 静态方法不在虚方法表中所以无法被继承 )</p><h4 id="私有方法" tabindex="-1"><a class="header-anchor" href="#私有方法"><span>私有方法</span></a></h4><p>私有方法是提供给接口内部使用的,不会被继承</p><h1 id="内部类" tabindex="-1"><a class="header-anchor" href="#内部类"><span>内部类</span></a></h1><h2 id="成员内部类" tabindex="-1"><a class="header-anchor" href="#成员内部类"><span>成员内部类</span></a></h2><p>在一个类的内部再定义一个类这个类就是内部类</p><p>内部类表示的事物是外部类的一部分 内部类单独出现没有任何意义</p><p>内部类可以直接访问外部类的成员，包括私有 外部类要访问内部类的成员，必须创建对象</p><p>jdk16之前内部类无法定义静态成员,jdk16之后可以</p><h2 id="静态内部类" tabindex="-1"><a class="header-anchor" href="#静态内部类"><span>静态内部类</span></a></h2><p>在内部类前加<code>static</code>修饰 静态内部类只能访问外部类中的静态变量和静态方法，如果想要访问非静态的需要创建对象。 通过外部类.内部类调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>public class Outer {</span></span>
<span class="line"><span>    public static class Inner {</span></span>
<span class="line"><span>        public void createInner() {</span></span>
<span class="line"><span>            System.out.println(&quot;Inner&quot;);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    Outer.Inner oi=new Outer.Inner();</span></span>
<span class="line"><span>    oi.createInner();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>非静态方法：先创建对象，用对象调用</li><li>静态方法：外部类名.内部类名.方法名();</li></ul><h2 id="局部内部类" tabindex="-1"><a class="header-anchor" href="#局部内部类"><span>局部内部类</span></a></h2><p>将内部类定义在方法里面就叫做局部内部类，类似于方法里面的局部变量外界是无法直接使用，需要在方法内部创建对象并使用。该类可以直接访问外部类的成员，也可以访问方法内的局部变量。</p><h2 id="匿名内部类" tabindex="-1"><a class="header-anchor" href="#匿名内部类"><span>匿名内部类</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>new 类名或接口名(){</span></span>
<span class="line"><span>	重写方法;</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Test externs Swim{</span></span>
<span class="line"><span>	new Swim(){</span></span>
<span class="line"><span>		@Override</span></span>
<span class="line"><span>		public void swim(){</span></span>
<span class="line"><span>			System.out.println(&quot;重写了游泳的方法&quot;);</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中new后面的Swim是表示创建了一个类的对象,它后面的大括号中的代码段才是类,大括号中的内容和被继承的类(Swim)是继承关系,即<code>new Swim()</code>后面的大括号是Swim类的子类,如果Swim是接口的话那二者就是实现关系 如上所述,可以使用一个变量接受匿名内部类的对象,也可之间使用匿名内部类的对象调用方法 ,上面的代码只是重写了匿名内部类,但还没有调用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Test externs Swim{</span></span>
<span class="line"><span>	Swim s = new Swim(){</span></span>
<span class="line"><span>		@Override</span></span>
<span class="line"><span>		public void swim(){</span></span>
<span class="line"><span>			System.out.println(&quot;重写了游泳的方法&quot;);</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>或:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Test externs Swim{</span></span>
<span class="line"><span>	new Swim(){</span></span>
<span class="line"><span>		@Override</span></span>
<span class="line"><span>		public void swim(){</span></span>
<span class="line"><span>			System.out.println(&quot;重写了游泳的方法&quot;);</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}.swim();</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,82)]))}const c=a(l,[["render",d]]),r=JSON.parse('{"path":"/back/java/3/","title":"3 类和对象","lang":"zh-CN","frontmatter":{"title":"3 类和对象","createTime":"2025/06/22 09:46:28","permalink":"/back/java/3/"},"readingTime":{"minutes":8.67,"words":2601},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Java/3 类和对象.md","headers":[]}');export{c as comp,r as data};
